:host { display: block; }
.agent-tool { border: var(--dimension-stroke-width-012) solid var(--color-border-tertiary); border-radius: var(--dimension-radius-050); }
summary { align-items: center; cursor: pointer; display: grid; gap: var(--dimension-space-050); grid-template-columns: auto minmax(0, 1fr) auto; list-style: none; padding: var(--dimension-space-075) var(--dimension-space-100); }
summary::-webkit-details-marker { display: none; }
.agent-tool__status { align-items: center; color: var(--color-foreground-faint-neutral); display: flex; }
.agent-tool--running .agent-tool__status, .agent-tool--queued .agent-tool__status { color: var(--color-foreground-faint-brand); }
.agent-tool--error .agent-tool__status, .agent-tool--denied .agent-tool__status { color: var(--color-foreground-bold-negative); }
.agent-tool__title { display: grid; gap: var(--dimension-space-025); }
details[open] .agent-tool__chevron { transform: rotate(90deg); }
.agent-tool__details { display: grid; gap: var(--dimension-space-075); padding: 0 var(--dimension-space-100) var(--dimension-space-100); }
section { display: grid; gap: var(--dimension-space-025); }
pre { background: var(--color-background-secondary); border-radius: var(--dimension-radius-050); margin: 0; overflow: auto; padding: var(--dimension-space-075); white-space: pre-wrap; }

@media (prefers-reduced-motion: no-preference) { .agent-tool__chevron { transition: transform var(--effect-motion-short-2); } }

import { Component, Prop, h, Host } from '@stencil/core';
import type { AgentToolState } from '../conversation-types';

@Component({ tag: 'ds-agent-tool-call', styleUrl: 'AgentToolCall.css', scoped: true })
export class AgentToolCall {
  @Prop() name: string = '';
  @Prop() label: string = '';
  @Prop() state: AgentToolState = 'queued';
  @Prop() input?: unknown;
  @Prop() output?: unknown;
  @Prop() error?: string;
  @Prop() open: boolean = false;

  private serialize(value: unknown) {
    if (value === undefined) return '';
    if (typeof value === 'string') return value;
    try { return JSON.stringify(value, null, 2); } catch { return String(value); }
  }

  render() {
    const active = this.state === 'queued' || this.state === 'running';
    const status = this.state.charAt(0).toUpperCase() + this.state.slice(1);
    return (
      <Host>
        <details class={`agent-tool agent-tool--${this.state}`} open={this.open}>
          <summary>
            <span class="agent-tool__status" aria-hidden="true">
              {active ? <ds-loader size="xs" color="inherit" /> : <ds-icon name={this.state === 'success' ? 'Check' : 'ErrorTriangle'} size="xs" color="inherit" />}
            </span>
            <span class="agent-tool__title">
              <ds-text variant="text-body-small" emphasis>{this.label || this.name}</ds-text>
              <ds-text variant="text-caption" color="secondary">{status}</ds-text>
            </span>
            <ds-icon class="agent-tool__chevron" name="ChevronRight" size="xs" color="inherit" />
          </summary>
          <div class="agent-tool__details">
            {this.input !== undefined ? <section><ds-text variant="text-caption" emphasis>Input</ds-text><pre>{this.serialize(this.input)}</pre></section> : null}
            {this.output !== undefined ? <section><ds-text variant="text-caption" emphasis>Output</ds-text><pre>{this.serialize(this.output)}</pre></section> : null}
            {this.error ? <section><ds-text variant="text-caption" emphasis>Error</ds-text><pre>{this.error}</pre></section> : null}
          </div>
        </details>
      </Host>
    );
  }
}
